export function getLogoUrl(ticker: string | null | undefined): string | null {
  if (!ticker) return null
  const safe = String(ticker).replace(/[^A-Za-z0-9._-]/g, '_').toUpperCase()
  return LOGO_MANIFEST[safe] ?? null
}
